import React, { useEffect, useState } from 'react';
import axios from 'axios';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const [currentSong, setCurrentSong] = useState(null);
    const [loading, setLoading] = useState(true);

    const SERVER_URL = 'http://localhost:5000';

    useEffect(() => {
        const fetchSongs = async () => {
            try {
                const res = await axios.get(`${SERVER_URL}/api/songs`);
                setSongs(res.data);
            } catch (err) {
                console.error("Lỗi lấy danh sách nhạc:", err);
            } finally {
                setLoading(false);
            }
        };
        fetchSongs();
    }, []);

    if (loading) return <div style={{ textAlign: 'center', marginTop: '50px' }}>Đang tải danh sách nhạc...</div>;

    return (
        <div style={{ padding: '20px', maxWidth: '900px', margin: '0 auto', paddingBottom: '120px' }}>
            <h2 style={{ textAlign: 'center', color: '#333', marginBottom: '30px', textTransform: 'uppercase', letterSpacing: '1px' }}>
                Danh Sách Bài Hát
            </h2>
            
            <div style={{ display: 'grid', gap: '20px' }}>
                {songs.length === 0 ? (
                    <div style={{ textAlign: 'center', color: '#999', padding: '40px', border: '2px dashed #ddd', borderRadius: '10px' }}>
                        Chưa có bài hát nào. Hãy nhấn <b>+ UPLOAD</b> để thêm nhạc nhé!
                    </div>
                ) : (
                    songs.map((song) => (
                        <div key={song._id} style={{
                            display: 'flex', 
                            alignItems: 'center', 
                            padding: '15px', 
                            border: '1px solid #eee', 
                            borderRadius: '12px',
                            background: currentSong?._id === song._id ? '#f0f9ff' : '#fff',
                            boxShadow: '0 4px 6px rgba(0,0,0,0.05)',
                            transition: 'transform 0.2s',
                            cursor: 'default'
                        }}>
                            {/* Ảnh bìa bài hát */}
                            <img 
                                src={song.imageUrl ? `${SERVER_URL}${song.imageUrl}` : 'https://via.placeholder.com/60'} 
                                alt="cover" 
                                style={{ width: '60px', height: '60px', borderRadius: '8px', marginRight: '20px', objectFit: 'cover', border: '1px solid #eee' }}
                            />
                            
                            <div style={{ flex: 1 }}>
                                <div style={{ fontWeight: 'bold', fontSize: '18px', color: '#2c3e50' }}>{song.title}</div>
                                <div style={{ fontSize: '14px', color: '#7f8c8d', marginTop: '4px' }}>{song.artist}</div>
                            </div>

                            {/* Nút Play thiết kế giống hình mẫu của bạn */}
                            <button 
                                onClick={() => setCurrentSong(song)}
                                style={{ 
                                    padding: '10px 40px', 
                                    cursor: 'pointer', 
                                    background: currentSong?._id === song._id ? '#1db954' : '#28a745', 
                                    color: '#fff', 
                                    border: 'none', 
                                    borderRadius: '6px',
                                    fontWeight: 'bold',
                                    fontSize: '14px',
                                    transition: '0.3s'
                                }}
                            >
                                {currentSong?._id === song._id ? 'ĐANG PHÁT' : 'PLAY'}
                            </button>
                        </div>
                    ))
                )}
            </div>

            {/* TRÌNH PHÁT NHẠC CỐ ĐỊNH (Player Bar) */}
            {currentSong && (
                <div style={{
                    position: 'fixed', bottom: 0, left: 0, right: 0, 
                    background: '#222', color: '#fff', padding: '15px 30px', 
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    boxShadow: '0 -5px 15px rgba(0,0,0,0.3)',
                    zIndex: 1000
                }}>
                    <div style={{ marginRight: '20px', textAlign: 'right', display: 'none' /* Hiện trên mobile */ }}>
                        <b style={{ color: '#1db954' }}>{currentSong.title}</b>
                    </div>
                    
                    <div style={{ width: '100%', maxWidth: '800px', display: 'flex', alignItems: 'center' }}>
                         <div style={{ marginRight: '20px', whiteSpace: 'nowrap' }}>
                            <span style={{ color: '#aaa', fontSize: '12px' }}>Đang phát:</span><br/>
                            <b style={{ fontSize: '14px' }}>{currentSong.title}</b>
                        </div>
                        <audio 
                            src={`${SERVER_URL}${currentSong.songUrl}`} 
                            controls 
                            autoPlay 
                            style={{ flex: 1, height: '40px' }}
                        />
                    </div>
                </div>
            )}
        </div>
    );
};

export default Home;
